NP_functionality.VERILOG_PROVIDED:
integer res_file, clock_counter, bp_counter;

initial
begin
  res_file = $fopen(DATA_file,"w");
  clock_counter = 0;
  bp_counter = 0;
end

always @(posedge clock)
begin  
  clock_counter <= clock_counter + 1;
  if(Mout_back_pressure == 1)
  begin
    bp_counter = bp_counter + 1;
  end
  if((Mout_oe_ram == 1 || Mout_we_ram == 1) && Mout_back_pressure == 0)  
  begin 
    $fwrite(res_file, "%0d,%0d,%0d,%0d,%0d \n", clock_counter, CHANNEL_NUMBER, node_id_dest, Mout_addr_ram, bp_counter);  
  end
end

integer res_file, clock_counter, bp_counter;

initial
begin
  res_file = $fopen(DATA_file,"w");
  clock_counter = 0;
  bp_counter = 0;
end

always @(posedge clock)
begin  
  clock_counter <= clock_counter + 1;
  if(Mout_back_pressure == 1)
  begin
    bp_counter = bp_counter + 1;
  end
  if((Mout_oe_ram == 1 || Mout_we_ram == 1) && Mout_back_pressure == 0)  
  begin 
    $fwrite(res_file, "%0d,%0d,%0d,%0d,%0d \n", clock_counter, M_tag[NODE_ID_SIZE-1:0], BANK_NUMBER, Mout_addr_ram, bp_counter);  
  end
end

reg [BITSIZE_ADDR+BITSIZE_DATA-1:0] o_0_reg;
reg o_0_valid_reg;
reg [BITSIZE_ADDR+BITSIZE_DATA-1:0] o_1_reg;
reg o_1_valid_reg;          
reg [BITSIZE_o_0-1:0] o_0;
reg o_0_valid;
reg [BITSIZE_o_1-1:0] o_1;
reg o_1_valid;
wire i_inside_addrbit;
wire i_outside_addrbit;

assign i_inside_addrbit = i_inside[BITSIZE_DATA+LEVEL];
assign i_outside_addrbit = i_outside[BITSIZE_DATA+LEVEL];
// o_1
always @(*)
begin
  if(i_inside_addrbit && i_inside_valid)
  begin
    o_1_reg = i_inside;
  end
  else
  begin
    o_1_reg = i_outside;
  end
end
// o_1_valid
always @(*)
begin
  if(i_inside_addrbit && i_inside_valid)
  begin
    o_1_valid_reg = 1'b1;
  end
  else if((i_outside_addrbit || (!i_inside_addrbit && i_inside_valid)) && i_outside_valid)
  begin
    o_1_valid_reg = 1'b1;
  end
  else
  begin
    o_1_valid_reg = 1'b0;
  end
end
// o_0
always @(*)
begin
  if(!i_inside_addrbit && i_inside_valid)
  begin
    o_0_reg = i_inside;
  end
  else
  begin
    o_0_reg = i_outside;
  end
end
// o_0_valid
always @(*)
begin
  if(!i_inside_addrbit && i_inside_valid)
  begin
    o_0_valid_reg = 1'b1;
  end
  else if((!i_outside_addrbit && i_outside_valid) || (i_outside_addrbit && i_outside_valid && i_inside_addrbit && i_inside_valid))
  begin
    o_0_valid_reg = 1'b1;
  end
  else
  begin
    o_0_valid_reg = 1'b0;
  end
end
generate
  if(REGISTERED==1)
  begin
    always @(posedge clock)
    begin
      o_1 <= o_1_reg;
      o_1_valid <= o_1_valid_reg;
      o_0 <= o_0_reg;
      o_0_valid <= o_0_valid_reg;
    end
  end
  else
    begin
    always @(*)
    begin
      o_1 = o_1_reg;
      o_1_valid = o_1_valid_reg;
      o_0 = o_0_reg;
      o_0_valid = o_0_valid_reg;
    end
  end
endgenerate

reg [BITSIZE_ADDR+BITSIZE_DATA-1:0] t_1_reg;
reg [BITSIZE_ADDR+BITSIZE_DATA-1:0] t_0_reg;
reg [BITSIZE_ADDR+BITSIZE_DATA-1:0] t_1_reg_t;
reg [BITSIZE_ADDR+BITSIZE_DATA-1:0] t_0_reg_t;

assign t_1 = t_1_reg_t;
assign t_0 = t_0_reg_t;

always @(*)
begin
  case(sel)
    2'b00:
    begin
      t_1_reg = i_inside;
      t_0_reg = i_outside;
    end
    2'b01:
    begin
      t_1_reg = i_outside;
      t_0_reg = i_inside;
    end
    2'b10:
    begin
      t_1_reg = i;
      t_0_reg = i_inside;
    end
    2'b11:
    begin
      t_1_reg = i_inside;
      t_0_reg = i;
    end
  endcase
end

generate
  if(REGISTERED==1)
  begin
    always @(posedge clock)
    begin
      t_1_reg_t <= t_1_reg;
      t_0_reg_t <= t_0_reg;
    end
  end
  else
  begin
    always @(*)
    begin
      t_1_reg_t = t_1_reg;
      t_0_reg_t  = t_0_reg;
    end
  end
endgenerate

parameter CTRL_BIT = ADDRESS[LEVEL];  
wire i_addrbit;
wire inside_addrbit;
wire outside_addrbit;
wire [BITSIZE_ADDR-1:0] addr_i;
wire [BITSIZE_ADDR-1:0] addr_inside;
wire [BITSIZE_ADDR-1:0] addr_outside;
wire is_addr_i;
wire is_addr_inside;
wire is_addr_outside;
wire [BITSIZE_ADDR+BITSIZE_DATA-1:0] t_1;
reg t_1_valid_reg;
wire [BITSIZE_ADDR+BITSIZE_DATA-1:0] t_0;
reg t_0_valid_reg;
wire go_inside_1;
wire go_inside_0;
wire go_outside_1;
wire go_outside_0;
wire go_i_1;
wire go_i_0;
reg o_0_valid_reg;
wire to_0_valid_reg;
reg o_1_valid_reg;
wire to_1_valid_reg;
reg o_valid_reg;
reg t_valid_reg;
reg [1:0] sel;


assign i_addrbit = i[BITSIZE_DATA+LEVEL];
assign inside_addrbit = i_inside[BITSIZE_DATA+LEVEL];
assign outside_addrbit = i_outside[BITSIZE_DATA+LEVEL];
assign addr_i = i[BITSIZE_ADDR+BITSIZE_DATA-1:BITSIZE_DATA];
assign addr_inside = i_inside[BITSIZE_ADDR+BITSIZE_DATA-1:BITSIZE_DATA];
assign addr_outside = i_outside[BITSIZE_ADDR+BITSIZE_DATA-1:BITSIZE_DATA];
assign is_addr_inside = addr_inside == ADDRESS;  
assign is_addr_outside = addr_outside == ADDRESS;  
assign is_addr_i = addr_i == ADDRESS;


assign go_inside_1 = inside_addrbit && i_inside_valid;
assign go_inside_0 = (!inside_addrbit) && i_inside_valid;

assign go_outside_1 = (outside_addrbit || go_inside_0) && i_outside_valid && !go_inside_1;
assign go_outside_0 = ((!outside_addrbit) || go_inside_1)  && i_outside_valid && !go_inside_0;

assign go_i_1 = (i_addrbit || go_inside_0) && i_valid && !go_outside_1 && !go_outside_0;
assign go_i_0 = (!i_addrbit || go_inside_1) && i_valid && !go_outside_0 && !go_outside_1;

always @(*)
begin
if(go_inside_1 && i_outside_valid)
  sel = 2'b00;
else if(go_inside_0 && i_outside_valid)
  sel = 2'b01;
else if(!i_inside_valid && outside_addrbit && i_outside_valid)
  sel = 2'b01;
else if(!i_inside_valid && !outside_addrbit && i_outside_valid)
  sel = 2'b00;
else if(go_inside_1 && !i_outside_valid)
  sel = 2'b11;
else if(go_inside_0 && !i_outside_valid)
  sel = 2'b10;
else if(i_addrbit)
  sel = 2'b10;
else
  sel = 2'b11;
end

swap_node3 #(.BITSIZE_i(BITSIZE_ADDR+BITSIZE_DATA), .BITSIZE_i_inside(BITSIZE_ADDR+BITSIZE_DATA), .BITSIZE_i_outside(BITSIZE_ADDR+BITSIZE_DATA),
           .BITSIZE_t_0(BITSIZE_ADDR+BITSIZE_DATA), .BITSIZE_t_1(BITSIZE_ADDR+BITSIZE_DATA),  
           .BITSIZE_ADDR(BITSIZE_ADDR), .BITSIZE_DATA(BITSIZE_DATA), .REGISTERED(REGISTERED)) swap_node_inst (.clock(clock), .i(i), .i_inside(i_inside), .i_outside(i_outside), .sel(sel), .t_0(t_0), .t_1(t_1));

// t_1_valid
always @(*)
begin
  if(go_inside_1)
  begin
    t_1_valid_reg = 1'b1;
  end
  else if(go_outside_1)
  begin
    t_1_valid_reg = 1'b1;
  end
  else if(go_i_1)
  begin
    t_1_valid_reg = 1'b1;
  end
  else
  begin
    t_1_valid_reg = 1'b0;
  end
end 
// o_0_valid
always @(*)
begin
  if(go_inside_0)
  begin
    t_0_valid_reg = 1'b1;
  end
  else if(go_outside_0)
  begin
    t_0_valid_reg = 1'b1;
  end
  else if(go_i_0)
  begin
    t_0_valid_reg = 1'b1;
  end
  else
  begin
    t_0_valid_reg = 1'b0;
  end
end

generate
  if(CTRL_BIT==1)
  begin
    always @(*)
    begin
      if(go_inside_1)
        t_valid_reg = is_addr_inside;
      else if(go_outside_1)
        t_valid_reg = is_addr_outside;
      else if(go_i_1)
        t_valid_reg = is_addr_i;
      else
        t_valid_reg = 1'b0;
    end
  end
  else
  begin
    always @(*)
    begin
      if(go_inside_0)
        t_valid_reg = is_addr_inside;
      else if(go_outside_0)
        t_valid_reg = is_addr_outside;
      else if(go_i_0)
        t_valid_reg = is_addr_i;
      else
        t_valid_reg = 1'b0;
    end
  end
endgenerate

generate
  if(CTRL_BIT==1)
  begin
    assign to_0_valid_reg = t_0_valid_reg;
    assign to_1_valid_reg = t_1_valid_reg && (!t_valid_reg || o_bp);
  end
  else
  begin
    assign to_0_valid_reg = t_0_valid_reg && (!t_valid_reg || o_bp);
    assign to_1_valid_reg = t_1_valid_reg;
  end
endgenerate

generate
  if(REGISTERED==1)
  begin
    always @(posedge clock)
    begin
      if(1RESET_VALUE)
      begin
        o_1_valid_reg <= 0;
        o_0_valid_reg <= 0;
        o_valid_reg <= 0;
      end
      else
      begin
        o_1_valid_reg <= to_1_valid_reg;
        o_0_valid_reg <= to_0_valid_reg;
        o_valid_reg <= t_valid_reg && !o_bp;
      end
    end
  end
  else
  begin
    always @(*)
    begin
      o_1_valid_reg = to_1_valid_reg;
      o_0_valid_reg = to_0_valid_reg;
      o_valid_reg = t_valid_reg && !o_bp; 
    end
  end
endgenerate

assign o_1 = t_1;
assign o_1_valid = o_1_valid_reg;
assign o_0 = t_0;
assign o_0_valid = o_0_valid_reg;
assign i_bp = i_valid && (go_outside_1 || go_outside_0);
assign o_valid = o_valid_reg;
generate
  if(CTRL_BIT==1)
  begin
    assign o = t_1;
  end
  else
  begin
    assign o = t_0;
  end
endgenerate

wire [BITSIZE_in1-1:0] inputarray [0:PORTSIZE_in1-1];
genvar i;
generate
for (i=0; i < PORTSIZE_in1; i=i+1)
  begin : MUX_pack_block
      assign inputarray[i] = in1[i*BITSIZE_in1 +: BITSIZE_in1];
  end
endgenerate

generate 
  if(SELECTOR_START == SELECTOR_END)
  begin
    assign out1 = inputarray[selector[SELECTOR_START]];
  end
  else
  begin
    assign out1 = inputarray[selector[SELECTOR_START - 1: SELECTOR_END]];
  end
endgenerate

generate 
  if(BUNDLE_START == BUNDLE_END)
  begin
    assign out1 = {in1[BITSIZE_in1-1:BANK_START],in1[BANK_END-1:0]};
  end
  else
  begin
    assign out1 = {in1[BITSIZE_in1-1:BUNDLE_START],in1[BUNDLE_END-1:BANK_START],in1[BANK_END-1:0]};
  end
endgenerate

localparam [NODE_ID_SIZE-1:0] NODE_ID_local= NODE_ID;  

assign noc_to_memory_i = Mout_oe_ram ? {node_id_dest,1'b0,Mout_addr_ram,Mout_Wdata_ram,Mout_data_ram_size,Mout_tag,NODE_ID_local} : {node_id_dest,1'b1,Mout_addr_ram,Mout_Wdata_ram,Mout_data_ram_size,Mout_tag,NODE_ID_local};
assign noc_to_memory_i_valid = (Mout_oe_ram || Mout_we_ram) && Mout_addr_ram >= BASE_ADDR;   

assign M_DataRdy_out = noc_from_memory_o_valid == 1;
assign M_Rdata_ram_out = (noc_from_memory_o_valid == 1) ? noc_from_memory_o[BITSIZE_M_Rdata_ram_out+BITSIZE_M_tag_out-1:BITSIZE_M_tag_out] : 0;
assign M_tag_out = (noc_from_memory_o_valid == 1) ? noc_from_memory_o[BITSIZE_M_tag_out-1:0] : 0;

reg Mout_oe_ram_out_reg;
reg Mout_oe_ram_out_reg_next;
reg Mout_we_ram_out_reg;
reg Mout_we_ram_out_reg_next;
reg [BITSIZE_Mout_addr_ram_out - 1 :0] Mout_addr_ram_out_reg;
reg [BITSIZE_Mout_addr_ram_out - 1 :0] Mout_addr_ram_out_reg_next;
reg [BITSIZE_Mout_Wdata_ram_out - 1 :0] Mout_Wdata_ram_out_reg;
reg [BITSIZE_Mout_Wdata_ram_out - 1 :0] Mout_Wdata_ram_out_reg_next;
reg [BITSIZE_Mout_data_ram_size_out - 1 :0] Mout_data_ram_size_out_reg;
reg [BITSIZE_Mout_data_ram_size_out - 1 :0] Mout_data_ram_size_out_reg_next;
reg [BITSIZE_Mout_tag_out - 1 :0] Mout_tag_out_reg;
reg [BITSIZE_Mout_tag_out - 1 :0] Mout_tag_out_reg_next;
reg Mout_back_pressure_out_reg;
reg noc_to_memory_o_valid_reg;
wire noc_to_memory_o_valid_next;
wire use_reg;

assign use_reg = Mout_back_pressure_out_reg || noc_to_memory_o_valid_reg;
assign noc_to_memory_o_valid_next = noc_to_memory_o_valid && ((Mout_back_pressure_out_reg && !Mout_back_pressure_out) || noc_to_memory_o_valid_reg); 

always @(posedge clock)
begin
  if(1RESET_VALUE)
  begin
    Mout_oe_ram_out_reg <= 0;
    Mout_we_ram_out_reg <= 0;
    Mout_addr_ram_out_reg <= 0;
    Mout_Wdata_ram_out_reg <= 0;
    Mout_data_ram_size_out_reg <= 0;
    Mout_tag_out_reg <= 0;
    Mout_back_pressure_out_reg <= 0;
    noc_to_memory_o_valid_reg <= 0;
  end
  else
  begin
    Mout_oe_ram_out_reg <= Mout_oe_ram_out_reg_next;
    Mout_we_ram_out_reg <= Mout_we_ram_out_reg_next;
    Mout_addr_ram_out_reg <= Mout_addr_ram_out_reg_next;
    Mout_Wdata_ram_out_reg <= Mout_Wdata_ram_out_reg_next;
    Mout_data_ram_size_out_reg <= Mout_data_ram_size_out_reg_next;
    Mout_tag_out_reg <= Mout_tag_out_reg_next;
    Mout_back_pressure_out_reg <= Mout_back_pressure_out;
    noc_to_memory_o_valid_reg <= noc_to_memory_o_valid_next;
  end
end

always @(*) 
begin
  if(Mout_back_pressure_out && noc_to_memory_o_valid)
  begin
    Mout_oe_ram_out_reg_next = noc_to_memory_o[BITSIZE_Mout_addr_ram_out+BITSIZE_Mout_Wdata_ram_out+BITSIZE_Mout_data_ram_size_out+BITSIZE_Mout_tag_out] == 1 ? 0 : 1;
    Mout_we_ram_out_reg_next = noc_to_memory_o[BITSIZE_Mout_addr_ram_out+BITSIZE_Mout_Wdata_ram_out+BITSIZE_Mout_data_ram_size_out+BITSIZE_Mout_tag_out] == 0 ? 0 : 1;
    Mout_addr_ram_out_reg_next = noc_to_memory_o[BITSIZE_Mout_addr_ram_out+BITSIZE_Mout_Wdata_ram_out+BITSIZE_Mout_data_ram_size_out+BITSIZE_Mout_tag_out-1:BITSIZE_Mout_Wdata_ram_out+BITSIZE_Mout_data_ram_size_out+BITSIZE_Mout_tag_out];
    Mout_Wdata_ram_out_reg_next = noc_to_memory_o[BITSIZE_Mout_Wdata_ram_out+BITSIZE_Mout_data_ram_size_out+BITSIZE_Mout_tag_out-1:BITSIZE_Mout_data_ram_size_out+BITSIZE_Mout_tag_out];
    Mout_data_ram_size_out_reg_next = noc_to_memory_o[BITSIZE_Mout_data_ram_size_out+BITSIZE_Mout_tag_out-1:BITSIZE_Mout_tag_out];  
    Mout_tag_out_reg_next = noc_to_memory_o[BITSIZE_Mout_tag_out-1:0];
  end
  else if(Mout_back_pressure_out)
  begin
    Mout_oe_ram_out_reg_next = Mout_oe_ram_out_reg;
    Mout_we_ram_out_reg_next = Mout_we_ram_out_reg;
    Mout_addr_ram_out_reg_next = Mout_addr_ram_out_reg;
    Mout_Wdata_ram_out_reg_next = Mout_Wdata_ram_out_reg;
    Mout_data_ram_size_out_reg_next = Mout_data_ram_size_out_reg;
    Mout_tag_out_reg_next = Mout_tag_out_reg;
  end
  else
  begin
    Mout_oe_ram_out_reg_next = 0;
    Mout_we_ram_out_reg_next = 0;
    Mout_addr_ram_out_reg_next = 0;
    Mout_Wdata_ram_out_reg_next = 0;
    Mout_data_ram_size_out_reg_next = 0;
    Mout_tag_out_reg_next = 0;
  end
end

assign Mout_oe_ram_out = use_reg ? Mout_oe_ram_out_reg : (noc_to_memory_o_valid ? (noc_to_memory_o[BITSIZE_Mout_addr_ram_out+BITSIZE_Mout_Wdata_ram_out+BITSIZE_Mout_data_ram_size_out+BITSIZE_Mout_tag_out] == 1 ? 0 : 1) : 0);
assign Mout_we_ram_out = use_reg ? Mout_we_ram_out_reg : (noc_to_memory_o_valid ? (noc_to_memory_o[BITSIZE_Mout_addr_ram_out+BITSIZE_Mout_Wdata_ram_out+BITSIZE_Mout_data_ram_size_out+BITSIZE_Mout_tag_out] == 0 ? 0 : 1) : 0);
