assign Mout_Wdata_ram_out = use_reg ? Mout_Wdata_ram_out_reg : (noc_to_memory_o_valid ? noc_to_memory_o[BITSIZE_Mout_Wdata_ram_out+BITSIZE_Mout_data_ram_size_out+BITSIZE_Mout_tag_out-1:BITSIZE_Mout_data_ram_size_out+BITSIZE_Mout_tag_out] : 0);
assign Mout_data_ram_size_out = use_reg ? Mout_data_ram_size_out_reg : (noc_to_memory_o_valid ? noc_to_memory_o[BITSIZE_Mout_data_ram_size_out+BITSIZE_Mout_tag_out-1:BITSIZE_Mout_tag_out] : 0);
assign Mout_tag_out = use_reg ? Mout_tag_out_reg : (noc_to_memory_o_valid ? noc_to_memory_o[BITSIZE_Mout_tag_out-1:0] : 0);
assign noc_from_memory_i = M_DataRdy ? {M_tag[NODE_ID_SIZE-1:0],M_Rdata_ram,M_tag[BITSIZE_M_tag-1 : NODE_ID_SIZE]} : 0;
assign noc_from_memory_i_valid = M_DataRdy ? 1'b1 : 0;
