      .i(in1_temp),
      .o(lower_out));
  end
  else if(BITSIZE_in1 < 8)
  begin
    wire [7:0] in1_temp, upper_in_temp;
    assign in1_temp = in1 | {8{1'b0}};
    assign upper_in_temp = upper_in | {8{1'b0}};
    multiple_priority_encoder_8_3 upper (.empty(empty_upper),
      .i(upper_in_temp),
      .o(upper_out));
    multiple_priority_encoder_8_3 lower (.empty(empty_lower),
      .i(in1_temp),
      .o(lower_out));
  end
  else if(BITSIZE_in1 < 16)
  begin
    wire [15:0] in1_temp, upper_in_temp;
    assign in1_temp = in1 | {16{1'b0}};
    assign upper_in_temp = upper_in | {16{1'b0}};
    multiple_priority_encoder_16_4 upper (.empty(empty_upper),
      .i(upper_in_temp),
      .o(upper_out));
    multiple_priority_encoder_16_4 lower (.empty(empty_lower),
      .i(in1_temp),
      .o(lower_out));
  end
  else if(BITSIZE_in1 < 32)
  begin
    wire [31:0] in1_temp, upper_in_temp;
    assign in1_temp = in1 | {32{1'b0}};
    assign upper_in_temp = upper_in | {32{1'b0}};
    multiple_priority_encoder_32_5 upper (.empty(empty_upper),
      .i(upper_in_temp),
      .o(upper_out));
    multiple_priority_encoder_32_5 lower (.empty(empty_lower),
      .i(in1_temp),
      .o(lower_out));
  end
  else if(BITSIZE_in1 < 64)
  begin
    wire [63:0] in1_temp, upper_in_temp;
    assign in1_temp = in1 | {64{1'b0}};
    assign upper_in_temp = upper_in | {64{1'b0}};
    multiple_priority_encoder_64_6 upper (.empty(empty_upper),
      .i(upper_in_temp),
      .o(upper_out));
    multiple_priority_encoder_64_6 lower (.empty(empty_lower),
      .i(in1_temp),
      .o(lower_out));
  end
  else
  begin
    // synthesis translate_off
    $fatal;
    // synthesis translate_on
  end
endgenerate

`ifndef POW_TO_2
`define POW_TO_2(x) \
  (x <= 2) ? 2 : \
  (x <= 4) ? 4 : \
  (x <= 8) ? 8 : \
  (x <= 16) ? 16 : \
  (x <= 32) ? 32 : \
  (x <= 64) ? 64 : \
  (x <= 128) ? 128 : \
  (x <= 256) ? 256 : \
  -1
`endif

localparam BITSIZE_in1_internal = `POW_TO_2(BITSIZE_in1);

wire [BITSIZE_in1_internal-1:0] in1_rev;
wire [BITSIZE_in1_internal-1:0] in1_temp;
wire [BITSIZE_out1-1:0] selector;

assign in1_temp = in1 | {BITSIZE_in1_internal{1'b0}};

genvar i;
generate
  for (i = 0; i < BITSIZE_in1_internal; i = i + 1) begin : reverse_bits
    assign in1_rev[i] = in1_temp[BITSIZE_in1_internal-1-i];
  end
endgenerate

priority_arbiter_core #(.BITSIZE_in1(BITSIZE_in1_internal),
.BITSIZE_out1(BITSIZE_out1)) priority_arbiter (.clock(clock),
.reset(reset),
.in1(in1_rev),
.out1(selector),
.valid(valid));

assign out1 = valid ? ~selector : 0;

reg [PORTSIZE_in1*BITSIZE_in1-1:0] rin1;
wire [PORTSIZE_in1*BITSIZE_in1-1:0] rin1_next;
wire temp;

assign temp = &rin1;
assign rin1_next = temp ? 0 : (rin1 | in1);

always @(posedge clock 1RESET_EDGE) 
begin
  if (1RESET_VALUE)
  begin
    rin1 <= 0;
  end
  else
  begin
    rin1 <= rin1_next;
  end
end

assign out1 = &rin1_next;
